import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _identify = {title: "Identify", jsx: <><h2 id="spell-identify-identify">Identify</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 299</Link><br/><strong>School</strong> <Link to="/spelldef/divination">divination</Link>; <strong>Level</strong> alchemist 1, arcanist 1, bard 1, investigator 1, medium 1, occultist 1, psychic 1, skald 1, sorcerer 1, spiritualist 1, summoner 1, unchained summoner 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (wine stirred with an owl's feather)<br/><strong>Range</strong> 60 ft.<br/><strong>Area</strong> cone-shaped emanation<br/><strong>Duration</strong> 3 rounds/level (D)<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell functions as <Link to="/spell/detect_magic">detect magic</Link>, except that it gives you a +10 enhancement bonus on Spellcraft checks made to identify the properties and command words of magic items in your possession. This spell does not allow you to identify artifacts.</p>
</>};
const _ignoble_form = {title: "Ignoble Form", jsx: <><h2 id="spell-ignoble_form-ignoble-form">Ignoble Form</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 16</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link> (<Link to="/spelldef/polymorph">polymorph</Link>); <strong>Level</strong> alchemist 2, antipaladin 2, arcanist 4, bard 2, druid 3, hunter 2, investigator 2, medium 2, ranger 2, skald 2, sorcerer 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a half-elf ear)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one drow<br/><strong>Duration</strong> 24 hours<br/><strong>Saving Throw</strong> Fortitude negates (harmless); <strong>Spell Resistance</strong> no</p><p>The target takes on the form of a half-elf from the surface world. Its skin, hair, and eyes change to match a specific human ethnicity. You can even change the target's facial features or produce light facial hair or stubble. The target loses its darkvision, light blindness, and light sensitivity traits, if it normally has them. The target gains low-light vision; a +3 racial bonus on a single Craft, Knowledge, Perform, or Profession skill of its choice; and both a +4 bonus on Bluff checks and a +10 bonus on Disguise checks to pass itself off as a half-elf.</p>
</>};
const _ill_omen = {title: "Ill Omen", jsx: <><h2 id="spell-ill_omen-ill-omen">Ill Omen</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 229</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/curse">curse</Link>, <Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> medium 1, mesmerist 1, psychic 1, witch 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (hair from a black cat)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level or until discharged<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You afflict the target with bad luck. On the next d20 roll the target makes, it must roll twice and take the less favorable result. For every five caster levels you have, the target must roll twice on an additional d20 roll (to a maximum of five rolls at 20th level).</p>
<p>A target who can speak and has at least one free hand and who is aware of the spell and its effects (such as from a Spellcraft check to identify the spell as it is cast) can negate one reroll by spending a move action to utter a brief prayer or good luck charm to appease the spirits of ill fortune.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-ill_omen--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Ill Omen</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 98</Link><br/>For the target's unlucky d20 rolls, it must roll three times and take the lowest result. Spending a move action to utter a prayer or good luck charm allows the target to roll twice instead of three times.</p>
<p><em>Augmented (4th):</em> If you expend two uses of mythic power, you afflict the target with especially foul luck. Any natural 20 it rolls counts as a natural 1 instead.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _illusion_of_calm = {title: "Illusion of Calm", jsx: <><h2 id="spell-illusion_of_calm-illusion-of-calm">Illusion of Calm</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 231</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> alchemist 1, arcanist 1, investigator 1, magus 1, mesmerist 1, occultist 1, psychic 1, red mantis assassin 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> personal<br/><strong>Target</strong> you<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will disbelieve (on hit, see below); <strong>Spell Resistance</strong> no</p><p>When casting this spell, you create an illusory double that takes the same space of you. That double makes it look like you are standing still, even when you are not. While under the effects of this spell, you do not provoke attacks of opportunity when you cast a spell, make a ranged attack with a thrown weapon, or move out of your first square during a move action. It does not hide ranged attacks made with any type of projectile weapon.</p>
<p>When a creature hits you with an attack of any type, it gains a saving throw to disbelieve the figment. On a successful saving throw, it successfully disbelieves and the spell's effect ends for that creature.</p>
</>};
const _illusion_of_treachery = {title: "Illusion of Treachery", jsx: <><h2 id="spell-illusion_of_treachery-illusion-of-treachery">Illusion of Treachery</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 216</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> antipaladin 3, arcanist 4, magus 4, mesmerist 3, occultist 4, psychic 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, F (a tiny marionette)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will disbelief; <strong>Spell Resistance</strong> yes</p><p>You create an illusion that takes the same space as a foe and mimics its movements perfectly. Whenever you cast a spell or throw a weapon, the illusion ceases mimicking the target's actions just long enough to make it look like the target cast the spell or threw the weapon simultaneously with you, such that witnesses who can see both you and the target can't tell with certainty who truly cast the spell or threw the weapon. Witnesses who can see only the target see it as the only apparent source. The subject of this spell doesn't provoke attacks of opportunity from these illusory actions. Each target of the attack or spell counts as interacting with the illusion and thus receives a save to disbelieve.</p>
<h3 id="spell-illusion_of_treachery-greater-illusion-of-treachery">Greater Illusion of Treachery</h3>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 217</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> antipaladin 4, arcanist 6, magus 6, mesmerist 4, occultist 5, psychic 5, sorcerer 6, wizard 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, F (a tiny marionette)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> you and one creature<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Will disbelief; <strong>Spell Resistance</strong> yes</p><p>This spell functions as illusion of treachery except that it also conceals your own actions (as illusion of calm) and renders invisible all spell effects and ranged attacks originating from you until they reach the attack's target (this doesn't cause the attack's target to be unable to avoid the attack, as they still see the attack originating from the spell's target).</p>
</>};
const _illusory_crowd = {title: "Illusory Crowd", jsx: <><h2 id="spell-illusory_crowd-illusory-crowd">Illusory Crowd</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 30</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> bard 1, shaman 1, skald 1, witch 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a shirt button)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> one 10-ft. cube of illusory people<br/><strong>Duration</strong> 1 minute/level (D)<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>This spell creates an illusion of a stationary group of people milling about. They can be of any humanoid race or ethnicity you are familiar with, and they speak a language of your choice that you know. To anyone not paying close attention, their conversations sound perfectly normal but are in fact repetitive and essentially meaningless. The crowd appears to be a group of typical citizens, and cannot duplicate any specific group, guild, or military squad.</p>
<p>The crowd affects movement and provides cover like a real crowd, but anyone who disbelieves the illusion can move and attack through the crowd without impediment. Each round a creature enters or makes an attack through a crowd-filled square, it can attempt a save to disbelieve the illusion. Similarly, any creature that spends a round listening to or talking to the crowd can attempt a save to disbelieve the illusion. If the group is placed in any terrain other than urban, each creature attempting a save to disbelieve the spell gains a +5 bonus on the save.</p>
</>};
const _illusory_hoard = {title: "Illusory Hoard", jsx: <><h2 id="spell-illusory_hoard-illusory-hoard">Illusory Hoard</h2>
<p><strong>Sources</strong> <Link to="/source/dragonslayers_handbook">Dragonslayer's Handbook pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/phantasm">phantasm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 5, bard 4, skald 4, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> S, M (an item from the hoard, see below)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (and see below); <strong>Spell Resistance</strong> yes</p><p>The spell forces the target to believe that nothing in its hoard is missing or has been disturbed. This spell fools all the senses, convincing the target that its hoard feels and behaves as it should. Only if the target tries to use an item from this illusory hoard for some other purpose does it receive another saving throw to disbelieve the effects of the spell (a wizard trying to use an illusory wand or a dragon trying to unlock a door with an illusory key). For the purposes of this spell, a hoard is any amount of treasure that is too big to be carried by the treasure's owner without magical tools such as bags of holding or portable holes, such as a dragon's hoard, a king's treasury, a merchant's strongbox, or a thief's hidden cache.</p>
<p>The material component is any item worth 10 gp or more taken from the original hoard. This item is consumed by the spell.</p>
</>};
const _illusory_maze = {title: "Illusory Maze", jsx: <><h2 id="spell-illusory_maze-illusory-maze">Illusory Maze</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 41</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 2, bard 2, skald 2, sorcerer 2, witch 2, wizard 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> 20-ft.-radius spread<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> yes</p><p>This spell creates the illusion of a translucent, ever-changing maze of glass in the target area. Creatures in the area who believe the maze to be real cannot move more than 5 feet continuously in any one direction and can't move diagonally, forcing them to take a circuitous route to their destination.</p>
</>};
const _illusory_poison = {title: "Illusory Poison", jsx: <><h2 id="spell-illusory_poison-illusory-poison">Illusory Poison</h2>
<p><strong>Sources</strong> <Link to="/source/gnomes_of_golarion">Gnomes of Golarion pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/phantasm">phantasm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, red mantis assassin 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> weapon touched<br/><strong>Duration</strong> 1 minute/level or until discharged (see text)<br/><strong>Saving Throw</strong> Will disbelief, then Fortitude (see text); <strong>Spell Resistance</strong> yes</p><p>You create a phantasm of an oily green phantasmal poison on the target weapon. The first creature hit by the poisoned weapon must make a Will save against the illusion spell; success means the spell has no effect and is expended from the weapon. If the creature fails its save, it believes it has been poisoned and must make Fortitude saves at the spell's DC to avoid suffering illusory poison damage.</p>
<p>Delay poison allows the target to ignore the effects of the phantasmal poison until the delay poison spell ends, at which time it may make a Will save to realize the poison is illusory and recover all illusory poison damage. Neutralize poison, lesser restoration, or restoration immediately recovers all damage from the spell. A successful <Link to="/spell/dispel_magic">dispel magic</Link> spell ends the effect of the illusion, as do spells that penetrate illusions (such as <Link to="/spell/true_seeing">true seeing</Link>). The target automatically recovers all illusory poison damage after 1 hour.</p>
<h4 id="spell-illusory_poison-phantasmal-poison">Phantasmal Poison</h4>
<p><strong>Type</strong> poison, injury; <strong>Save</strong> Fortitude DC as the spell<br/><strong>Frequency</strong> 1/round for 6 rounds<br/><strong>Effect</strong> 1d3 Str damage; <strong>Cure</strong> 1 save</p>
</>};
const _illusory_script = {title: "Illusory Script", jsx: <><h2 id="spell-illusory_script-illusory-script">Illusory Script</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 299</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/phantasm">phantasm</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 3, bard 3, mesmerist 3, occultist 3, psychic 3, red mantis assassin 3, skald 3, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 minute per page<br/><strong>Components</strong> V, S, M (lead-based ink worth 50 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched object weighing no more than 10 lbs.<br/><strong>Duration</strong> one day/level<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>You write instructions or other information on parchment, paper, or any suitable writing material. The illusory script appears to be some form of foreign or magical writing. Only the person (or people) designated by you at the time of the casting can read the writing; it's unintelligible to any other character.</p>
<p>Any unauthorized creature attempting to read the script triggers a potent illusory effect and must make a saving throw. A successful saving throw means the creature can look away with only a mild sense of disorientation. Failure means the creature is subject to a suggestion implanted in the script by you at the time the illusory script spell was cast. The suggestion lasts only 30 minutes. Typical suggestions include "Close the book and leave," "Forget the existence of this note," and so forth. If successfully dispelled by <Link to="/spell/dispel_magic">dispel magic</Link>, the illusory script and its secret message disappear. The hidden message can be read by a combination of the <Link to="/spell/true_seeing">true seeing</Link> spell with the <Link to="/spell/read_magic">read magic</Link> or <Link to="/spell/comprehend_languages">comprehend languages</Link> spell.</p>
</>};
const _illusory_wall = {title: "Illusory Wall", jsx: <><h2 id="spell-illusory_wall-illusory-wall">Illusory Wall</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 299</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 4, mesmerist 4, occultist 4, psychic 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> image 1 ft. by 10 ft. by 10 ft.<br/><strong>Duration</strong> permanent<br/><strong>Saving Throw</strong> Will disbelief (if interacted with); <strong>Spell Resistance</strong> no</p><p>This spell creates the illusion of a wall, floor, ceiling, or similar surface. It appears absolutely real when viewed, but physical objects can pass through it without difficulty. When the spell is used to hide pits, traps, or normal doors, any detection abilities that do not require sight work normally. Touch or a probing search reveals the true nature of the surface, though such measures do not cause the illusion to disappear. Although the caster can see through his illusory wall, other creatures cannot, even if they succeed at their will save (but they do learn that it is not real).</p>
</>};
const _imbue_army_special_ability = {title: "Imbue Army Special Ability", jsx: <><h2 id="spell-imbue_army_special_ability-imbue-army-special-ability">Imbue Army Special Ability</h2>
<p><strong>Sources</strong> <Link to="/source/quests_and_campaigns">Quests and Campaigns pg. 29</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 9, oracle 9<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, F (a silver mirror worth 100 gp)<br/><strong>Range</strong> 1 hex<br/><strong>Target</strong> one army<br/><strong>Duration</strong> 1 battle<br/><strong>Saving Throw</strong> none or Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You imbue the target with an <Link to="/rule/special_abilities_ucp">army special ability</Link> possessed by the army's commander. The army is treated as if it consists of units who all possess the chosen special ability. This special ability is in addition to any special abilities the army inherently possessed prior to the casting of the spell.</p>
</>};
const _imbue_hex = {title: "Imbue Hex", jsx: <><h2 id="spell-imbue_hex-imbue-hex">Imbue Hex</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_origins">Advanced Class Origins pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> shaman 5, witch 5<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, M/DF (a hag's whisker)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched; see text<br/><strong>Duration</strong> permanent or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes</p><p>You transfer a single hex you know to the target, and give that target the ability to use the hex. The transferred hex's variable characteristics function according to your level, not the level of the recipient. Only a creature with Intelligence and Wisdom scores of at least 9 can receive this effect. To use this hex, the target must be able to speak and move freely. Once it uses the hex, the spell ends (though any effects of the hex still last for the full duration). You can transfer only a hex-not a major or grand hex-with this ability.</p>
<p>Once you cast imbue hex, you cannot use the transferred hex until the spell is discharged, dispelled, or dismissed.</p>
</>};
const _imbue_with_addiction = {title: "Imbue With Addiction", jsx: <><h2 id="spell-imbue_with_addiction-imbue-with-addiction">Imbue With Addiction</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 19</Link>, <Link to="/source/magical_marketplace">Magical Marketplace pg. 24</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> alchemist 2, arcanist 3, investigator 2, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a dose of an addictive drug or substance)<br/><strong>Range</strong> touch<br/><strong>Target</strong> one living creature<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>The target immediately becomes addicted to the drug used as the material component during the casting of the spell. If the target was ever addicted to the drug at any point in the past, it takes a -4 penalty on its saving throw.</p>
</>};
const _imbue_with_aura = {title: "Imbue with Aura", jsx: <><h2 id="spell-imbue_with_aura-imbue-with-aura">Imbue with Aura</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 225</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> cleric 2, oracle 2, warpriest 2<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates (see text); <strong>Spell Resistance</strong> yes</p><p>You infuse another creature with your divine aura, causing the target to radiate an aura identical to your own clerical aura. The target's actual alignment is not changed, but spells like <Link to="/spell/detect_evil">detect evil</Link> or <Link to="/spell/detect_good">detect good</Link> detect only the aura, not the creature's actual alignment. For the duration of this spell, effects influenced by the target's alignment function according to the imposed aura, not the creature's actual aura. When the spell ends, the target's aura returns to normal, and alignment-affecting magic affects it according to its actual alignment.</p>
</>};
const _imbue_with_elemental_might = {title: "Imbue with Elemental Might", jsx: <><h2 id="spell-imbue_with_elemental_might-imbue-with-elemental-might">Imbue with Elemental Might</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 203</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [see text]; <strong>Level</strong> arcanist 2, bloodrager 2, cleric 2, magus 2, oracle 2, shaman 2, sorcerer 2, warpriest 2, wizard 2<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched; see text<br/><strong>Duration</strong> 24 hours or until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>This spell functions like imbue with spell ability, except you transfer the use of your elemental assault ability to the target. The target must have an Intelligence score of at least 5 to use the ability. The imbued elemental assault functions exactly like yours, except the ability's duration is based on the target's level or Hit Dice. Once you cast this spell, you cannot use your elemental assault ability until the duration of the spell is over.</p>
</>};
const _imbue_with_flight = {title: "Imbue with Flight", jsx: <><h2 id="spell-imbue_with_flight-imbue-with-flight">Imbue with Flight</h2>
<p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 15</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 4, red mantis assassin 4, sorcerer 4, wizard 4<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, M (handful of down)<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> 1 hour/level (D)<br/><strong>Saving Throw</strong> Will negates (object, harmless); <strong>Spell Resistance</strong> yes (object, harmless)</p><p>You grant a touched Large or smaller object the ability to fly at a speed of 40 feet with average maneuverability. It can ascend at half speed and descend at double speed. The targeted object flies as you direct it, using your Fly skill for any difficult maneuvers. You must be within close range (25 ft. + 5 ft./2 levels) of the object to direct it, and moving it requires a move action. If not directed, the object hovers in place (no Fly check required). The maximum weight of the object and anything carried by it is 500 pounds per caster level (maximum 10,000 pounds).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-imbue_with_flight--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Imbue with Flight</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_origins">Mythic Origins pg. 15</Link><br/>If you expend one use of mythic power, you double the maximum weight of the object you can imbue with flight. You can expend additional uses of mythic power to increase the maximum size of the object you can imbue with flight. Imbuing a Huge object requires two uses of mythic power, imbuing a Gargantuan object requires four uses, and imbuing a Colossal object requires eight uses. These costs include the expenditure to cast a mythic spell, and count toward doubling the weight limit of the spell.</p>
<p>Two or more casters can cast this spell in concert to share the mythic power cost. Each caster must expend an additional use of mythic power to cooperate; this does not count toward the other costs or effects of the spell. The group chooses which caster has control of the flight. As a full-round action, the controlling caster can cede control to another caster involved in the original casting of the spell.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _imbue_with_spell_ability = {title: "Imbue with Spell Ability", jsx: <><h2 id="spell-imbue_with_spell_ability-imbue-with-spell-ability">Imbue with Spell Ability</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 299</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 4, oracle 4, shaman 4, spiritualist 4, warpriest 4<br/><strong>Casting Time</strong> 10 minutes<br/><strong>Components</strong> V, S, DF<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched; see text<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You transfer some of your currently prepared spells, and the ability to cast them, to another creature. Only a creature with an Intelligence score of at least 5 and a Wisdom score of at least 9 can receive this boon. Only cleric spells from the schools of abjuration, divination, and conjuration (healing) can be transferred. The number and level of spells that the subject can be granted depends on its Hit Dice; even multiple castings of imbue with spell ability can't exceed this limit.</p>
<ScrollContainer id="spell-imbue_with_spell_ability--table-0"><table>
<thead>
<tr>
<th>HD of Recipient</th>
<th>Spells Imbued</th>
</tr>
</thead>
<tbody><tr>
<td>2 or lower</td>
<td>One 1st-level spell</td>
</tr>
<tr>
<td>3-4</td>
<td>One or two 1st-level spells</td>
</tr>
<tr>
<td>5 or higher</td>
<td>One or two 1st-level spells and one 2nd-level spell</td>
</tr>
</tbody></table></ScrollContainer>
<p>The transferred spell's variable characteristics (range, duration, area, and the like) function according to your level, not the level of the recipient.</p>
<p>Once you cast imbue with spell ability, you cannot prepare a new 4th-level spell to replace it until the recipient uses the imbued spells or is slain, or until you dismiss the imbue with spell ability spell. In the meantime, you remain responsible to your deity or your principles for the use to which the spell is put. If the number of 4th-level spells you can cast decreases, and that number drops below your current number of active imbue with spell ability spells, the more recently cast imbued spells are dispelled.</p>
<p>To cast a spell with a verbal component, the subject must be able to speak. To cast a spell with a somatic component, it must be able to move freely. To cast a spell with a material component or focus, it must have the materials or focus.</p>
</>};
const _impart_mind = {title: "Impart Mind", jsx: <><h2 id="spell-impart_mind-impart-mind">Impart Mind</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_magic">Inner Sea Magic pg. 57</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> arcanist 6, cleric 6, magus 5, oracle 6, sorcerer 6, warpriest 6, wizard 6<br/><strong>Casting Time</strong> 2 rounds<br/><strong>Components</strong> V, S, M (diamond dust worth at least 1,000 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> permanent nonintelligent magic item touched<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell grants the target magic item temporary intelligence by siphoning off a tiny portion of your own mind to infuse the object. Only permanent magic items may be enhanced by this spell-one-use items and charged items cannot be affected by impart mind. Intelligent magic items cannot be affected by impart mind.</p>
<p>When you cast impart mind on a magic item, the item gains an Intelligence, Wisdom, and Charisma score of 10 and gains your alignment. You have no special control over the item once it becomes intelligent, although since it has your alignment, personality conflicts with items you wield won't be a problem. Determine the item's ego normally, as per the rules on intelligent items in the Core Rulebook.</p>
<p>An item made intelligent via impart mind communicates via speech and has normal senses to a range of 60 feet. It speaks and reads one language known by you - if you know multiple languages, you may choose which language the item knows.</p>
<p>When you cast impart mind on an item, roll once on <Link to="/rule/intelligent_item_powers">Table 15-24</Link> to randomly determine the item's power-add your caster level to this roll. By expending additional diamond dust in excess of the 1,000 gp worth of material components required to cast this spell, you can gain further bonuses on the d% roll made to determine the item's power. Every additional 100 gp in diamond dust you use in excess grants a cumulative +1 bonus to the roll, up to a maximum additional bonus equal to your caster level. If the item gains the ability to cast a spell, determine the spell it can cast randomly from spells you know of the appropriate level. If the item gains ranks in a skill, it gains ranks in a random skill in which you have at least 1 rank.</p>
<p>If you roll above 100, then you can choose one item power on Table 15-24 to grant the item, and the item gains a special purpose. Roll once on Tables <Link to="/rule/special_purpose_items">15-25</Link> and <Link to="/rule/dedicated_powers">15-26</Link> to determine what the item's special purpose and dedicated powers are. These d% rolls are not modified by your caster level or any additional powdered gems you used to cast the spell.</p>
<p>Once this spell ends, the item reverts to its previous nature - if you cast this spell on the item again, it gains entirely different powers as determined by a new set of rolls.</p>
</>};
const _impede_speech = {title: "Impede Speech", jsx: <><h2 id="spell-impede_speech-impede-speech">Impede Speech</h2>
<p><strong>Sources</strong> <Link to="/source/second_darkness_players_guide">Second Darkness Player's Guide pg. 27</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> arcanist 3, bard 2, skald 2, sorcerer 3, wizard 3<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>This minor curse interferes with the target's ability to speak. On a failed save, the target has difficulty stringing words together. Only with great concentration can he communicate intelligibly. Speaking in combat becomes a move-equivalent action rather than a free action. If the target attempts to cast a spell with a verbal component, he has a 50% chance of making an error and losing the spell. Even if he can successfully cast a spell, doing so takes 1 round if the spell's normal casting time is less than 1 round. If the spell's casting time is usually 1 round or longer, its casting time doubles (up until the end of impede speech). Impede speech cannot be dispelled, but <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/remove_curse">remove curse</Link>, or <Link to="/spell/wish">wish</Link> can end it prematurely.</p>
</>};
const _impenetrable_veil = {title: "Impenetrable Veil", jsx: <><h2 id="spell-impenetrable_veil-impenetrable-veil">Impenetrable Veil</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 25</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 9, bard 6, mesmerist 6, psychic 9, skald 6, sorcerer 9, spiritualist 6, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (dust from the Dimension of Dreams worth 1,250 gp)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 10 minutes/level<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You enchant the target so it is nearly impossible to detect by both magical and mundane means, granting it the following benefits. The target gains a bonus on Stealth checks equal to half your caster level, and can use Stealth to hide from all creatures attempting to perceive it, even when it lacks concealment or cover. It can attempt a Stealth check to avoid detection from creatures using blindsight, blindsense, or any ability that functions as either (such as lifesense or tremorsense). Furthermore, the target leaves no trail and cannot be tracked unless it chooses to leave a trail. If a creature attempts to discern the target's presence or location using divination magic (including magic items with a divination aura such as a crystal ball), that creature must succeed at a caster level check with a DC equal to the target's Stealth bonus to discern any information about the target, and on a failed check cannot do so for the spell's duration.</p>
</>};
const _implant_false_reading = {title: "Implant False Reading", jsx: <><h2 id="spell-implant_false_reading-implant-false-reading">Implant False Reading</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 173</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/glamer">glamer</Link>); <strong>Level</strong> mesmerist 2, occultist 2, psychic 2<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> object touched<br/><strong>Duration</strong> 1 day/level<br/><strong>Saving Throw</strong> none, see text; <strong>Spell Resistance</strong> no</p><p>You implant a false psychometric reading into an object, imbuing the item with misleading information that might be learned from the <Link to="/spell/object_reading">object reading</Link> spell or through the <Link to="/skill/psychometry">psychometry</Link> occult skill unlock. This information might fool enemies, create a false history, or pass on secret messages through objects to psychically attuned allies. You can implant any information you wish that could be implanted by the charge object spell, as well as up to one piece of information per 3 levels that could be attained using psychometry or the object reading spell. You can detail this information in any way you see fit, either making up a previous owner and circumstances involving the object from whole cloth, or attempting to emulate the biographical information and fictional accounts of a specific individual's experience with the object.</p>
<p>During the spell's duration, creatures reading the object through the object reading spell or the psychometry occult skill unlock receive this false information in place of an item's true history if they fail a Will saving throw. Creatures that succeed at their saves still detect and receive the false information, but recognize it for what is and are able to discern the fictitious information from the item's true history without difficulty.</p>
<p>This spell masks its own magical aura, causing the target to not register as magical to detect spells and similar effects. This masking doesn't conceal any other magical auras on the object, and can be overcome in the same ways as magic aura.</p>
</>};
const _implant_urge = {title: "Implant Urge", jsx: <><h2 id="spell-implant_urge-implant-urge">Implant Urge</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/enchantment">enchantment</Link> (<Link to="/spelldef/compulsion">compulsion</Link>) [<Link to="/spelldef/mind_affecting">mind-affecting</Link>]; <strong>Level</strong> arcanist 1, bard 1, medium 1, mesmerist 1, skald 1, sorcerer 1, spiritualist 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature<br/><strong>Duration</strong> 1 hour/level<br/><strong>Saving Throw</strong> Will partial; <strong>Spell Resistance</strong> yes</p><p>You make the target unconsciously desire a goal you define when you cast this spell. The DC of any Diplomacy check to ask the target to act in a way that it believes will lead it toward that goal decreases by 5. The target takes a -2 penalty on saving throws against mind-affecting effects that compel it to act in a way that it believes will lead it toward that goal. Spells that reveal the target's goals or thoughts reveal the implanted urge as the target's most important goal and the target does not register as thinking of anything else as long as it is presented with the focus of its urge or a way to move toward its goal. Anyone studying the target's thoughts can notice the implanted nature of this urge with a successful caster level check.</p>
</>};
const _implosion = {title: "Implosion", jsx: <><h2 id="spell-implosion-implosion">Implosion</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 299</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link>; <strong>Level</strong> cleric 9, oracle 9, psychic 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one corporeal creature/round<br/><strong>Duration</strong> concentration (up to 1 round per 2 levels)<br/><strong>Saving Throw</strong> Fortitude negates; <strong>Spell Resistance</strong> yes</p><p>This spell causes a destructive resonance in a corporeal creature's body. Each round you concentrate (including the first), you can cause one creature to collapse in on itself, inflicting 10 points of damage per caster level. If you break concentration, the spell immediately ends, though any implosions that have already happened remain in effect. You can target a particular creature only once with each casting of the spell. Implosion has no effect on creatures in gaseous form or on incorporeal creatures.</p>
</>};
const _impossible_angles = {title: "Impossible Angles", jsx: <><h2 id="spell-impossible_angles-impossible-angles">Impossible Angles</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 121</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> arcanist 5, medium 3, mesmerist 4, occultist 4, psychic 5, sorcerer 5, wizard 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M (a melted prism)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> contiguous area up to one 5-foot cube/caster level (S)<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You cause the surrounding area to appear to distort. The angles and corners of the area subtly twist and contort, creating unnatural and impossible shapes. Any creature entering the area must succeed at a Will save or become disoriented. Disoriented characters treat the area as difficult terrain and are sickened. In addition, whenever a disoriented creature uses an action to move (including taking a 5-foot step if it can do so in difficult terrain), roll 1d8 to see which direction it moves, in a similar manner to determining where a splash weapon lands on a miss. On a 1, the creature moves in its intended direction, with 2 through 8 rotating around the creature's starting square in a clockwise direction. Only the creature's first 5 feet of movement each round are affected in this way - it can move normally for any remaining movement, either from the same action or from later actions, as the creature acclimatizes to the distortion. An affected creature can attempt a new Will save each round to end the disoriented effect. A creature that leaves the area and re-enters must attempt the saving throw again, even if it succeeded at its initial save.</p>
</>};
const _imprisonment = {title: "Imprisonment", jsx: <><h2 id="spell-imprisonment-imprisonment">Imprisonment</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link>; <strong>Level</strong> arcanist 9, psychic 9, sorcerer 9, wizard 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates; see text; <strong>Spell Resistance</strong> yes</p><p>When you cast imprisonment and touch a creature, it is entombed in a state of suspended animation (see the <Link to="/spell/temporal_stasis">temporal stasis</Link> spell) in a small sphere far beneath the surface of the ground. The subject remains there unless a freedom spell is cast at the locale where the imprisonment took place. Magical search by a crystal ball, a locate object spell, or some other similar divination does not reveal the fact that a creature is imprisoned, but discern location does. A wish or miracle spell will not free the recipient, but will reveal where it is entombed. If you know the target's name and some facts about its life, the target takes a -4 penalty on its save.</p>
</>};
const _improve_trap = {title: "Improve Trap", jsx: <><h2 id="spell-improve_trap-improve-trap">Improve Trap</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 137</Link><br/><strong>School</strong> <Link to="/spelldef/transmutation">transmutation</Link>; <strong>Level</strong> antipaladin 2, arcanist 3, druid 3, hunter 2, inquisitor 3, ranger 2, red mantis assassin 3, sorcerer 3, witch 3, wizard 3<br/><strong>Casting Time</strong> 1 minute<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one trap<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will negates (object); <strong>Spell Resistance</strong> yes (object)</p><blockquote>
<p><em><Link to="/race/kobold">Kobolds</Link> have access to the following spell.</em></p>
</blockquote>
<p>When this spell is cast upon a trap, it improves one specific element of the trap chosen at the time of casting. The caster can improve the trap in any of the following ways (each one raises the trap's CR by +1).</p>
<ul>
<li>Increase DC of the Perception check required to locate the trap by +5.</li>
<li>Increase DC of the Disable Device check required to disarm trap by +5.</li>
<li>Increase the trap's attack bonus or saving throw by +2.</li>
</ul>
<p>To cast this on a trap, you must know that the trap exists and its precise location. A trap can only have one improvement from this spell at a time. A second casting changes the improvement on the trap, but does not add another improvement.</p>
</>};
const _incendiary_cloud = {title: "Incendiary Cloud", jsx: <><h2 id="spell-incendiary_cloud-incendiary-cloud">Incendiary Cloud</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/creation">creation</Link>) [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 8, sorcerer 8, summoner 6, wizard 8<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Area</strong> cloud spreads in 20-ft. radius, 20 ft. high<br/><strong>Duration</strong> 1 round/level (D)<br/><strong>Saving Throw</strong> Reflex half, see text; <strong>Spell Resistance</strong> no</p><p>An incendiary cloud spell creates a cloud of roiling smoke shot through with white-hot embers. The smoke obscures all sight as a fog cloud does. In addition, the white-hot embers within the cloud deal 6d6 points of fire damage to everything within the cloud on your turn each round. All targets can make Reflex saves each round to take half damage.</p>
<p>As with a cloudkill spell, the smoke moves away from you at 10 feet per round. Figure out the smoke's new spread each round based on its new point of origin, which is 10 feet farther away from where you were when you cast the spell. By concentrating, you can make the cloud move as much as 60 feet each round. Any portion of the cloud that would extend beyond your maximum range dissipates harmlessly, reducing the remainder's spread thereafter.</p>
<p>As with fog cloud, wind disperses the smoke, and the spell can't be cast underwater.</p>
</>};
const _incendiary_runes = {title: "Incendiary Runes", jsx: <><h2 id="spell-incendiary_runes-incendiary-runes">Incendiary Runes</h2>
<p><strong>Sources</strong> <Link to="/source/black_markets">Black Markets pg. 31</Link><br/><strong>School</strong> <Link to="/spelldef/abjuration">abjuration</Link> [<Link to="/spelldef/fire">fire</Link>]; <strong>Level</strong> arcanist 1, sorcerer 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> one touched object weighing no more than 10 lbs.<br/><strong>Duration</strong> permanent until discharged<br/><strong>Saving Throw</strong> Reflex partial; <strong>Spell Resistance</strong> yes</p><p>This spell functions as <Link to="/spell/explosive_runes">explosive runes</Link>, except it creates a small surge of flames rather than an explosion of force. The runes automatically deal 1d6 points of fire damage to any creatures and objects in adjacent squares, and those creatures and objects catch fire unless they succeed at Reflex saves.</p>
</>};
const _incessant_buzzing = {title: "Incessant Buzzing", jsx: <><h2 id="spell-incessant_buzzing-incessant-buzzing">Incessant Buzzing</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_temples">Inner Sea Temples pg. 62</Link><br/><strong>School</strong> <Link to="/spelldef/illusion">illusion</Link> (<Link to="/spelldef/figment">figment</Link>); <strong>Level</strong> antipaladin 1, arcanist 1, bard 1, psychic 1, shaman 1, skald 1, sorcerer 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S, M/DF (insect wing)<br/><strong>Range</strong> medium (100 ft. + 10 ft./level)<br/><strong>Effect</strong> 10-ft.-diameter sphere<br/><strong>Duration</strong> 1 round/level<br/><strong>Saving Throw</strong> Will negates; <strong>Spell Resistance</strong> yes</p><p>You summon an illusory swarm of angry wasps that fills a 10-foot-diameter sphere. You can summon it so that it shares an area with other creatures, and you can move it up to 40 feet each round as a move action. Creatures caught inside the swarm's area of effect cannot use skills that require patience or concentration. Additionally, spellcasters within the area must succeed at a caster level check (DC = 20 + level of spell to be cast) in order to cast spells. On a failed caster level check, the spell is lost. While the buzzing is unpleasant, it is not so loud as to drown out other noises or make communication difficult.</p>
</>};
const _incorporeal_chains = {title: "Incorporeal Chains", jsx: <><h2 id="spell-incorporeal_chains-incorporeal-chains">Incorporeal Chains</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 174</Link><br/><strong>School</strong> <Link to="/spelldef/evocation">evocation</Link> [<Link to="/spelldef/force">force</Link>]; <strong>Level</strong> psychic 6, spiritualist 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one incorporeal creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> concentration<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> yes</p><p>You summon ghostly chains to bind incorporeal creatures. The chains' CMB is equal to your caster level + your Intelligence modifier. Roll only once for the entire spell effect and apply the result to all targeted incorporeal creatures.</p>
<p>If the chains succeed in grappling an incorporeal creature, the creature takes an amount of damage equal to 1d8 + your key spellcasting ability score modifier and gains the grappled condition. Grappled opponents can't move without first breaking the grapple. The spell prohibits all other movement unless the creature breaks the grapple first (although dimensional magic and the like still work as normal). Each round you concentrate, the chains continue grappling their current targets (though they don't seek out targets they aren't currently grappling). The incorporeal chains receive a +5 bonus on grapple combat maneuver checks against opponents the chains are already grappling, but can't move foes or pin foes. Each round the incorporeal chains succeed at a grapple combat maneuver check, they deal an additional amount of damage equal to 1d8 + your key spellcasting ability score modifier. The CMD of incorporeal chains, for the purposes of escaping the grapple, is equal to 10 + its CMB. If you move out of range of any of the grappled creatures, the chains cease grappling those creatures.</p>
</>};
const _infernal_challenger = {title: "Infernal Challenger", jsx: <><h2 id="spell-infernal_challenger-infernal-challenger">Infernal Challenger</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 98</Link>, <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 60</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/calling">calling</Link>) [<Link to="/spelldef/lawful">lawful</Link>]; <strong>Level</strong> arcanist 3, cleric 3, oracle 3, sorcerer 3, summoner 3, unchained summoner 3, warpriest 3, wizard 3<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, F/DF (an iron badge or medallion)<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Effect</strong> one called bearded devil and testing ground; see text<br/><strong>Duration</strong> 1 minute/level<br/><strong>Saving Throw</strong> none; <strong>Spell Resistance</strong> no</p><p>This spell summons a bearded devil, causing it to appear where you designate. The area within a 50-foot radius of where the devil appears is ringed with a smoldering, red glow. This area is the testing ground. To successfully cast this spell, no creature other than the devil's challenger (see below) can be within this area while the spell is being cast.</p>
<p>On the round it appears, the devil identifies itself (typically by name and with a brief recitation of honors) and states it is prepared to do battle with a sole mortal champion. In the same round, either you or a creature you designate while casting the spell must identify the devil's challenger. For the duration of the spell, the devil does everything in its power to kill the challenger. You do not control the devil or have any influence over how it conducts itself in battle, but the devil cannot leave the testing ground. Unlike with summon monster and similar spells, you cannot dismiss the devil. Rather, the conjured devil remains until any one of the following criteria is met: it is reduced below 0 hit points or otherwise defeated, its challenger is slain, its challenger leaves the testing ground, or it takes damage from any source other than its challenger. Upon any of these occurrences, the devil vanishes.</p>
<p>Conjuring a devil is typically an evil act. If cast for any purpose besides the administering of a <Link to="/rule/hellknights">Hellknight</Link> test, this spell has the evil descriptor.</p>
</>};
const _infernal_healing = {title: "Infernal Healing", jsx: <><h2 id="spell-infernal_healing-infernal-healing">Infernal Healing</h2>
<p><strong>Sources</strong> <Link to="/source/hells_vengeance_players_guide">Hell's Vengeance Player's Guide pg. 11</Link>, <Link to="/source/pathfinder_29_mother_of_flies">Pathfinder #29: Mother of Flies pg. 67</Link>, <Link to="/source/gods_and_magic">Gods and Magic pg. 7</Link>, <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 295</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 1, bloodrager 1, cleric 1, magus 1, oracle 1, sorcerer 1, summoner 1, unchained summoner 1, warpriest 1, witch 1, wizard 1<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (1 drop of devil blood or 1 dose of unholy water)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>You anoint a wounded creature with devil's blood or unholy water, giving it fast healing 1. This ability cannot repair damage caused by silver weapons, good-aligned weapons, or spells or effects with the good descriptor. The target detects as evil for the duration of the spell and can sense the evil of the magic, though this has no long-term effect on the target's alignment.</p>
<h3 id="spell-infernal_healing-greater-infernal-healing">Greater Infernal Healing</h3>
<p><strong>Sources</strong> <Link to="/source/hells_vengeance_players_guide">Hell's Vengeance Player's Guide pg. 11</Link><br/><strong>School</strong> <Link to="/spelldef/conjuration">conjuration</Link> (<Link to="/spelldef/healing">healing</Link>) [<Link to="/spelldef/evil">evil</Link>]; <strong>Level</strong> arcanist 4, cleric 4, magus 4, oracle 4, sorcerer 4, summoner 4, unchained summoner 4, warpriest 4, witch 4, wizard 4<br/><strong>Casting Time</strong> 1 round<br/><strong>Components</strong> V, S, M (1 drop of devil blood or 1 dose of unholy water)<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> 1 minute<br/><strong>Saving Throw</strong> Will negates (harmless); <strong>Spell Resistance</strong> yes (harmless)</p><p>As per infernal healing, except the target gains fast healing 4 and the target detects as an evil cleric.</p>
</>};
const _inflict_critical_wounds = {hasJL:true,title: "Inflict Critical Wounds", jsx: <><div className="jumpList" id="spell-inflict_critical_wounds-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-inflict_critical_wounds-mythic_inflict_critical_wounds">Mythic Inflict Critical Wounds</InnerLink></li><li><InnerLink toTop to="spell-inflict_critical_wounds-mass-inflict-critical-wounds">Mass Inflict Critical Wounds</InnerLink></li></ul></div><h2 id="spell-inflict_critical_wounds-inflict-critical-wounds">Inflict Critical Wounds</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 4, inquisitor 4, occultist 4, oracle 4, shaman 4, spiritualist 4, warpriest 4, witch 5<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will half; <strong>Spell Resistance</strong> yes</p><p>This spell functions like <Link to="/spell/inflict_light_wounds">inflict light wounds</Link>, except that you deal 4d8 points of damage + 1 point per caster level (maximum +20).</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-inflict_critical_wounds--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-inflict_critical_wounds-mythic_inflict_critical_wounds" data-hash-target>Mythic Inflict Critical Wounds</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 98</Link></p>
<p>The damage dealt increases to 8d8 points of damage + 2 points per caster level (maximum +40). A living target is sickened for 1 round per caster level (maximum 20 rounds) if it fails its saving throw.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-inflict_critical_wounds-mass-inflict-critical-wounds" data-hash-target>Mass Inflict Critical Wounds</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 8, oracle 8, shaman 8, witch 9<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will half; <strong>Spell Resistance</strong> yes</p><p>This spell functions like <Link to="/spell/mass_inflict_light_wounds">mass inflict light wounds</Link>, except that it deals 4d8 points of damage + 1 point per caster level (maximum +40).</p>
</>};
const _inflict_light_wounds = {hasJL:true,title: "Inflict Light Wounds", jsx: <><div className="jumpList" id="spell-inflict_light_wounds-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="spell-inflict_light_wounds-mythic_inflict_light_wounds">Mythic Inflict Light Wounds</InnerLink></li><li><InnerLink toTop to="spell-inflict_light_wounds-mass-inflict-light-wounds">Mass Inflict Light Wounds</InnerLink></li></ul></div><h2 id="spell-inflict_light_wounds-inflict-light-wounds">Inflict Light Wounds</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> antipaladin 1, cleric 1, inquisitor 1, occultist 1, oracle 1, shaman 1, spiritualist 1, warpriest 1, witch 1<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> touch<br/><strong>Target</strong> creature touched<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will half; <strong>Spell Resistance</strong> yes</p><p>When laying your hand upon a creature, you channel negative energy that deals 1d8 points of damage + 1 point per caster level (maximum +5).</p>
<p>Since undead are powered by negative energy, this spell cures such a creature of a like amount of damage, rather than harming it.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="spell-inflict_light_wounds--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col" id="spell-inflict_light_wounds-mythic_inflict_light_wounds" data-hash-target>Mythic Inflict Light Wounds</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 99</Link></p>
<p>The damage dealt increases to 2d8 points of damage + 2 points per caster level (maximum +10). A living target is sickened for 1 round per caster level (maximum 5 rounds) if it fails its saving throw.</p>
</td></tr></tbody></table></ScrollContainer></div><h3 id="spell-inflict_light_wounds-mass-inflict-light-wounds" data-hash-target>Mass Inflict Light Wounds</h3>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 300</Link><br/><strong>School</strong> <Link to="/spelldef/necromancy">necromancy</Link>; <strong>Level</strong> cleric 5, inquisitor 5, occultist 5, oracle 5, shaman 5, warpriest 5, witch 6<br/><strong>Casting Time</strong> 1 standard action<br/><strong>Components</strong> V, S<br/><strong>Range</strong> close (25 ft. + 5 ft./2 levels)<br/><strong>Target</strong> one creature/level, no two of which can be more than 30 ft. apart<br/><strong>Duration</strong> instantaneous<br/><strong>Saving Throw</strong> Will half; <strong>Spell Resistance</strong> yes</p><p>Negative energy spreads out in all directions from the point of origin, dealing 1d8 points of damage + 1 point per caster level (maximum +25) to nearby living enemies.</p>
<p>Like other <Link to="/main/inflict_spells">inflict spells</Link>, mass inflict light wounds cures undead in its area rather than damaging them. A cleric capable of spontaneously casting inflict spells can also spontaneously cast mass inflict spells.</p>
</>};
